<?php
namespace Tests\Unit;
use App\Services\Trading\PositionManagementService;
use Tests\TestCase;
class PositionManagementServiceTest extends TestCase
{protected function state(array $over=[]):array{return array_replace_recursive(['schema_version'=>'trading_position_state_v1','status'=>'condition_observed','position_id'=>'position-bumi-1','ticker'=>'BUMI','position_side'=>'long','lifecycle'=>['observed_at'=>'2026-07-01T10:00:00+07:00'],'protection_checks'=>['stop_reference_available'=>true,'stop_reference_breached'=>true,'target_reference_available'=>true,'target_reference_reached'=>false],'reason_codes'=>['POSITION_STOP_REFERENCE_BREACHED']],$over);}protected function managed():array{return ['schema_version'=>'trading_managed_position_v1','status'=>'open_reference','position_id'=>'position-bumi-1','ticker'=>'BUMI','side'=>'long','quantity'=>1000,'currency'=>'IDR','entry_price'=>100,'opened_at'=>'2026-06-20T09:00:00+07:00','existing_protection'=>['stop_reference'=>['status'=>'available','price'=>90,'source'=>['type'=>'explicit_input','identifier'=>'stop']], 'target_reference'=>['status'=>'available','price'=>110,'source'=>['type'=>'explicit_input','identifier'=>'target']]],'source'=>['type'=>'synthetic_test_fixture','identifier'=>'managed'],'approved_for_execution'=>false,'synthetic_test_only'=>true];}protected function policy(?array $rules=null):array{return ['schema_version'=>'trading_position_management_policy_v1','status'=>'reference_only','policy_id'=>'policy-1','policy_version'=>'management_reference_policy_v1','position_id'=>'position-bumi-1','ticker'=>'BUMI','supported_side'=>'long','rules'=>$rules??[['rule_id'=>'review-stop-breach','condition'=>'stop_reference_breached','candidate_type'=>'protection_breach_review','priority'=>100,'enabled'=>true],['rule_id'=>'review-target-reach','condition'=>'target_reference_reached','candidate_type'=>'target_reached_review','priority'=>90,'enabled'=>true]],'source'=>['type'=>'synthetic_test_fixture','identifier'=>'policy'],'approved_for_selection'=>false,'approved_for_execution'=>false,'synthetic_test_only'=>true];}
public function test_entry_scope_not_required():void{$r=(new PositionManagementService())->evaluate(['decision_scope'=>'entry_evaluation']);$this->assertSame('trading_position_management_v1_2',$r['schema_version']);$this->assertSame('not_required',$r['status']);$this->assertSame('trading_position_management_policy_evaluation_v1',$r['policy_evaluation']['schema_version']);$this->assertSame('trading_position_management_risk_v1',$r['management_risk']['schema_version']);$this->assertSame('not_required',$r['management_risk']['status']);$this->assertSame('trading_position_management_review_plan_v1',$r['review_plan']['schema_version']);$this->assertSame('not_required',$r['review_plan']['status']);$this->assertNull($r['management_action_candidate']);}
public function test_monitoring_no_condition_has_no_implicit_hold():void{$svc=new PositionManagementService();$r=$svc->evaluate(['decision_scope'=>'position_management','position_state'=>$this->state(['status'=>'monitoring_reference','protection_checks'=>['stop_reference_available'=>true,'stop_reference_breached'=>false,'target_reference_available'=>true,'target_reference_reached'=>false],'reason_codes'=>[]]),'position_management_policy'=>$this->policy()]);$this->assertSame('monitoring_reference',$r['status']);$this->assertSame('no_condition',$r['policy_evaluation']['status']);$this->assertSame('unavailable',$r['management_candidate']['status']);$this->assertNull($r['selected_management_action']);$this->assertContains('POSITION_MANAGEMENT_NO_IMPLICIT_HOLD',$r['warnings']);}
public function test_stop_breach_without_and_with_policy():void{$svc=new PositionManagementService();$no=$svc->evaluate(['decision_scope'=>'position_management','position_state'=>$this->state()]);$this->assertSame('unavailable',$no['policy_evaluation']['status']);$this->assertSame('unavailable',$no['management_candidate']['status']);$with=$svc->evaluate(['decision_scope'=>'position_management','position_state'=>$this->state(),'position_management_policy'=>$this->policy(),'managed_position'=>$this->managed(),'decision_at'=>'2026-07-01T10:00:00+07:00']);$this->assertSame('matched_reference_rule',$with['policy_evaluation']['status']);$this->assertSame('policy_hypothesis',$with['management_candidate']['status']);$this->assertSame('condition_risk_observed',$with['management_risk']['status']);$this->assertSame('review_context_ready',$with['review_plan']['status']);$this->assertSame('candidate_reference_only',$with['management_selection']['status']);$this->assertNull($with['selected_management_action']);$this->assertNull($with['promoted_management_action']);$this->assertNull($with['executable_instruction']);}
public function test_target_and_missing_protection_policy():void{$svc=new PositionManagementService();$target=$svc->evaluate(['decision_scope'=>'position_management','position_state'=>$this->state(['protection_checks'=>['stop_reference_available'=>true,'stop_reference_breached'=>false,'target_reference_available'=>true,'target_reference_reached'=>true],'reason_codes'=>['POSITION_TARGET_REFERENCE_REACHED']]),'position_management_policy'=>$this->policy(),'managed_position'=>$this->managed(),'decision_at'=>'2026-07-01T10:00:00+07:00']);$this->assertSame('target_reached_review',$target['management_candidate']['candidate_type']);$missing=$svc->evaluate(['decision_scope'=>'position_management','position_state'=>$this->state(['status'=>'partial','protection_checks'=>['stop_reference_available'=>false,'stop_reference_breached'=>null,'target_reference_available'=>true,'target_reference_reached'=>false],'reason_codes'=>['POSITION_PROTECTION_REFERENCE_UNAVAILABLE']]),'managed_position'=>$this->managed(),'position_management_policy'=>$this->policy([['rule_id'=>'review-missing','condition'=>'protection_reference_missing','candidate_type'=>'protection_missing_review','priority'=>1,'enabled'=>true]]),'decision_at'=>'2026-07-01T10:00:00+07:00']);$this->assertSame('protection_missing_review',$missing['management_candidate']['candidate_type']);}
public function test_validator_rejects_action():void{$svc=new PositionManagementService();$r=$svc->evaluate(['decision_scope'=>'entry_evaluation']);$r['management_action_candidate']='HOLD_POSITION';$this->expectException(\InvalidArgumentException::class);$svc->validatePositionManagement($r);}}
